const qwen = async (messages, model, opts = {}) => {
  const base = ($env.DASHSCOPE_BASE_URL || 'https://dashscope-intl.aliyuncs.com/compatible-mode/v1').replace(/\/$/, '');
  const res = await this.helpers.httpRequest({
    method: 'POST', url: base + '/chat/completions',
    headers: { Authorization: 'Bearer ' + ($env.DASHSCOPE_API_KEY || ''), 'Content-Type': 'application/json' },
    body: Object.assign({ model, temperature: 0, messages }, opts), json: true,
  });
  return res.choices?.[0]?.message?.content ?? '';
};
const esc = (s) => String(s).replace(/'/g, "''");
const body = $json.body ?? $json;
const diff = (body.diff || body.patch || '').toString().slice(0, 12000);
if (!diff.trim()) return [{ json: { verdict: 'error', error: 'no diff provided (POST {"diff": "..."})' } }];
const coder = $env.QWEN_CODER_MODEL || 'qwen3-coder-plus';
const askIssues = async (sys) => {
  const out = await qwen([{ role: 'system', content: sys }, { role: 'user', content: 'Diff:\n' + diff }],
    coder, { response_format: { type: 'json_object' } });
  try { return JSON.parse(out).issues || []; } catch (e) { return []; }
};
const roles = [
  ['correctness', 'Find logic bugs, edge cases, and incorrect behavior.'],
  ['security', 'Find security holes: injection, authz, secrets, unsafe deserialization.'],
  ['style', 'Find readability and test-coverage gaps.'],
];
const fmt = ' List concrete issues only. Respond as JSON {"issues":[{"severity":"high|med|low","note":"..."}]}.';
const [roleResults, baseIssues] = await Promise.all([
  Promise.all(roles.map(async ([role, brief]) =>
    ({ role, issues: await askIssues(`You are the ${role} reviewer. ${brief}${fmt}`) }))),
  askIssues('You are a senior code reviewer doing a single-pass review.' + fmt),
]);
const merged = [].concat(...roleResults.map(r => r.issues.map(i => ({ ...i, role: r.role }))));
const negOut = await qwen([
  { role: 'system', content: 'Reconcile multiple reviewers into ONE verdict. Deduplicate, rank by severity, resolve disagreements. Respond as JSON {"verdict":"approve|request_changes","summary":"...","ranked_issues":[{"severity":"...","note":"...","roles":["..."]}]}.' },
  { role: 'user', content: 'Reviewer findings:\n' + JSON.stringify(merged) },
], ($env.QWEN_CHAT_MODEL || 'qwen-plus'), { response_format: { type: 'json_object' } });
let verdict; try { verdict = JSON.parse(negOut); } catch (e) { verdict = { verdict: 'request_changes', summary: negOut, ranked_issues: [] }; }
return [{ json: {
  verdict,
  role_findings: roleResults,
  metric: { team_issue_count: merged.length, baseline_issue_count: baseIssues.length, delta: merged.length - baseIssues.length },
} }];
